request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?reachableName WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "0ae2e7d8093840cc8a65c475b6275cae" .

  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .

  ?start bbo:name "Kaufwunsch" ;
         tai:belongsTo ?choreo .

  ?ber bbo:name "Beratung" ;
        tai:belongsTo ?choreo .

  FILTER EXISTS {
    ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?ber .
  }

  OPTIONAL { ?ber bbo:name ?reachableName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelId ?orgId WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId ?modelId ;
         tai:belongsTo ?org .
  ?org bbo:name ?orgId .
  FILTER(CONTAINS(LCASE(STR(?modelId)), LCASE("0ae2e7d8093840cc8a65c475b6275cae")))
}
LIMIT 25
